5206 InstCombinerImpl::pushFreezeToPreventPoisonFromPropagating(FreezeInst &OrigFI) {
5207   // Try to push freeze through instructions that propagate but don't produce
5208   // poison as far as possible. If an operand of freeze does not produce poison
5209   // then push the freeze through to the operands that are not guaranteed
5210   // non-poison. The actual transform is as follows.
5211   //   Op1 = ...                        ; Op1 can be poison
5212   //   Op0 = Inst(Op1, NonPoisonOps...)
5213   //   ... = Freeze(Op0)
5214   // =>
5215   //   Op1 = ...
5216   //   Op1.fr = Freeze(Op1)
5217   //   ... = Inst(Op1.fr, NonPoisonOps...)
5218 
5219   auto CanPushFreeze = [](Value *V) {
5220     if (!isa<Instruction>(V) || isa<PHINode>(V))
5221       return false;
5222 
5223     // Don't push through an existing freeze. Otherwise we can repeatedly
5224     // create redundant freeze instructions during instcombine iterations.
5225     if (isa<FreezeInst>(V))
5226       return false;
5227 
5228     // We can't push the freeze through an instruction which can itself create
5229     // poison.  If the only source of new poison is flags, we can simply
5230     // strip them (since we know the only use is the freeze and nothing can
5231     // benefit from them.)
5232     return !canCreateUndefOrPoison(cast<Operator>(V),
5233                                    /*ConsiderFlagsAndMetadata*/ false);
5234   };
5235 
5236   // Pushing freezes up long instruction chains can be expensive. Instead,
5237   // we directly push the freeze all the way to the leaves. However, we leave
5238   // deduplication of freezes on the same value for freezeOtherUses().
5239   Use *OrigUse = &OrigFI.getOperandUse(0);
5240   SmallPtrSet<Instruction *, 8> Visited;
5241   SmallVector<Use *, 8> Worklist;
5242   Worklist.push_back(OrigUse);
5243   while (!Worklist.empty()) {
5244     auto *U = Worklist.pop_back_val();
5245     Value *V = U->get();
5246     if (!CanPushFreeze(V)) {
5247       // If we can't push through the original instruction, abort the transform.
5248       if (U == OrigUse)
5249         return nullptr;
5250 
5251       auto *UserI = cast<Instruction>(U->getUser());
5252       Builder.SetInsertPoint(UserI);
5253       Value *Frozen = Builder.CreateFreeze(V, V->getName() + ".fr");
5254       U->set(Frozen);
5255       continue;
5256     }
5257 
5258     auto *I = cast<Instruction>(V);
5259     if (!Visited.insert(I).second)
5260       continue;
5261 
5262     // reverse() to emit freezes in a more natural order.
5263     for (Use &Op : reverse(I->operands())) {
5264       Value *OpV = Op.get();
5265       if (isa<MetadataAsValue>(OpV) || isGuaranteedNotToBeUndefOrPoison(OpV))
5266         continue;
5267       Worklist.push_back(&Op);
5268     }
5269 
5270     I->dropPoisonGeneratingAnnotations();
5271     this->Worklist.add(I);
5272   }
5273 
5274   return OrigUse->get();
5275 }
